SELECT COMMODITY_DESC AS commodity, SECTOR_DESC AS sector, GROUP_DESC AS commodity_group, SOURCE_DESC AS source, STATISTICCAT_DESC AS statistic, SHORT_DESC AS series, UNIT_DESC AS unit, CLASS_DESC AS class, PRODN_PRACTICE_DESC AS production_practice, UTIL_PRACTICE_DESC AS utilization_practice, DOMAIN_DESC AS domain, DOMAINCAT_DESC AS domain_category, AGG_LEVEL_DESC AS agg_level, STATE_ALPHA AS state_code, STATE_NAME AS state, ASD_DESC AS agricultural_district, COUNTY_NAME AS county, REGION_DESC AS region, LOCATION_DESC AS location, TRY_CAST("YEAR" AS INTEGER) AS year, FREQ_DESC AS frequency, REFERENCE_PERIOD_DESC AS reference_period, NULLIF(TRIM(WEEK_ENDING), '') AS week_ending, TRY_CAST(REPLACE(TRIM(VALUE), ',', '') AS DOUBLE) AS value, TRY_CAST(REPLACE(TRIM("CV_%"), ',', '') AS DOUBLE) AS cv_percent FROM "usda-nass-rice"
